const fs = require\('fs'\);

// Replicate the parser logic
const data = fs.readFileSync\('mz_545_1_format0.mid'\);
const ab = data.buffer.slice\(data.byteOffset, data.byteOffset + data.byteLength\);
const dv = new DataView\(ab\);

function readVarLen\(data, pos\) {
  let value = 0;
  let byte;
  do {
    byte = data.getUint8\(pos++\);
    value = \(value << 7\) | \(byte & 0x7f\);
  } while \(byte & 0x80\);
  return { value, pos };
}

const ticksPerBeat = dv.getUint16\(12\);
const trackLen = dv.getUint32\(18\);
let pos = 22;
const end = pos + trackLen;

let lastStatus = 0;
let totalTicks = 0;
const notes = [];
const tempoMap = [{ tick: 0, tempo: 500000 }];

while \(pos < end\) {
  const delta = readVarLen\(dv, pos\);
  pos = delta.pos;
  totalTicks += delta.value;

  let status = dv.getUint8\(pos\);
  if \(status < 0x80\) {
    status = lastStatus;
  } else {
    pos++;
    lastStatus = status;
  }

  const type = status & 0xf0;

  if \(status === 0xff\) {
    const metaType = dv.getUint8\(pos++\);
    const metaLen = readVarLen\(dv, pos\);
    pos = metaLen.pos;
    if \(metaType === 0x51 && metaLen.value === 3\) {
      const tempo = \(dv.getUint8\(pos\) << 16\) | \(dv.getUint8\(pos + 1\) << 8\) | dv.getUint8\(pos + 2\);
      tempoMap.push\({ tick: totalTicks, tempo }\);
    }
    pos += metaLen.value;
  } else if \(type === 0x90\) {
    const note = dv.getUint8\(pos++\);
    const vel = dv.getUint8\(pos++\);
    if \(vel > 0\) notes.push\({ tick: totalTicks, note, velocity: vel }\);
  } else if \(type === 0x80\) {
    pos += 2;
  } else if \(type === 0xb0 || type === 0xa0 || type === 0xe0\) {
    pos += 2;
  } else if \(type === 0xc0 || type === 0xd0\) {
    pos += 1;
  } else if \(type === 0xf0 || type === 0xf7\) {
    const sysLen = readVarLen\(dv, pos\);
    pos = sysLen.pos + sysLen.value;
  }
}

function tickToSeconds\(tick\) {
  let time = 0;
  let prevTick = 0;
  let currentTempo = tempoMap[0].tempo;
  for \(let i = 1; i < tempoMap.length; i++\) {
    if \(tempoMap[i].tick >= tick\) break;
    time += \(\(tempoMap[i].tick - prevTick\) / ticksPerBeat\) * \(currentTempo / 1000000\);
    prevTick = tempoMap[i].tick;
    currentTempo = tempoMap[i].tempo;
  }
  time += \(\(tick - prevTick\) / ticksPerBeat\) * \(currentTempo / 1000000\);
  return time;
}

const result = notes.map\(n => \({
  time: tickToSeconds\(n.tick\),
  note: n.note,
  velocity: n.velocity,
}\)\);

console.log\('Total notes parsed:', result.length\);
console.log\('First 3:', result.slice\(0, 3\)\);
console.log\('Last 3:', result.slice\(-3\)\);
console.log\('Duration \(last note time\):', result[result.length - 1].time.toFixed\(2\), 's'\);
console.log\('Tempos found:', tempoMap.length\);
" 2>&1)

